interface User {
  id: number;
  name: string;
  email: string;
}

interface Order {
  orderId: string;
  amount: number;
  status: 'pending' | 'completed' | 'cancelled';
}

interface Metrics {
  cpuUsage: number;
  memoryUsage: number;
  activeUsers: number;
}

// 2. 定义超时辅助函数
const createTimeout = (ms: number) =>
  new Promise<never>((_, reject) =>
    setTimeout(() => reject(new Error('Request Timeout')), ms)
  );

// 3. 定义安全请求辅助函数 (处理单个接口的超时与错误)
async function safeFetch<T>(url: string, fallback: T): Promise<T> {
  try {
    // 使用 Promise.race 实现超时控制 (这里设定 5000ms 超时)
    const response = await Promise.race([
      fetch(url),
      createTimeout(5000),
    ]);

    if (!response.ok) {
      throw new Error(`HTTP error! status: ${response.status}`);
    }

    return await response.json();
  } catch (error) {
    // 优雅降级：捕获错误并返回默认值，不抛出异常
    console.warn(`Failed to fetch ${url}:`, error);
    return fallback;
  }
}

// 4. 主函数实现
export async function fetchDashboardData() {
  try {
    // 使用 Promise.all 并发请求
    const [user, orders, metrics] = await Promise.all([
      safeFetch<User>('/api/user', null as any),
      safeFetch<Order[]>('/api/orders', []),
      safeFetch<Metrics>('/api/metrics', {
        cpuUsage: 0,
        memoryUsage: 0,
        activeUsers: 0,
      }),
    ]);

    return {
      user,
      orders,
      metrics,
      timestamp: new Date().toISOString(),
    };
  } catch (error) {
    // 兜底处理：防止 Promise.all 整体抛出未处理异常
    console.error('Dashboard data fetch failed completely:', error);
    return {
      user: null,
      orders: [],
      metrics: { cpuUsage: 0, memoryUsage: 0, activeUsers: 0 },
      timestamp: new Date().toISOString(),
    };
  }
}
